39	inline auto pick_free_port() -> uint16_t
40	{
41	  const int s = ::socket(AF_INET, SOCK_STREAM, 0);
42	  if (s < 0)
43	    throw std::runtime_error("pick_free_port: socket");
44	
45	  sockaddr_in addr{};
46	  addr.sin_family      = AF_INET;
47	  addr.sin_addr.s_addr = htonl(INADDR_LOOPBACK);
48	  addr.sin_port        = 0;
49	
50	  if (::bind(s, reinterpret_cast<sockaddr*>(&addr), sizeof(addr)) < 0) {
51	    ::close(s);
52	    throw std::runtime_error("pick_free_port: bind");
53	  }
54	  socklen_t len = sizeof(addr);
55	  if (::getsockname(s, reinterpret_cast<sockaddr*>(&addr), &len) < 0) {
56	    ::close(s);
57	    throw std::runtime_error("pick_free_port: getsockname");
58	  }
59	  ::close(s);
60	  return ntohs(addr.sin_port);
61	}
62	
63	// Thrown by connect_loopback when the watched child exits before the
64	// gdbstub becomes reachable (typically: bad --qemu-binary path).
65	struct ChildExitedDuringConnect
66	{
67	  int status;
68	};
69	
70	inline auto connect_loopback(uint16_t port,
71	                             std::chrono::milliseconds timeout,
72	                             pid_t child_pid = -1) -> int
73	{
74	  const auto deadline = std::chrono::steady_clock::now() + timeout;
75	  while (std::chrono::steady_clock::now() < deadline) {
76	    const int s = ::socket(AF_INET, SOCK_STREAM, 0);
77	    if (s < 0)
78	      throw std::runtime_error("connect_loopback: socket");
79	    sockaddr_in addr{};
80	    addr.sin_family      = AF_INET;
81	    addr.sin_addr.s_addr = htonl(INADDR_LOOPBACK);
82	    addr.sin_port        = htons(port);
83	    if (::connect(s, reinterpret_cast<sockaddr*>(&addr), sizeof(addr)) == 0)
84	      return s;
85	    ::close(s);
86	    if (child_pid > 0) {
87	      int wstat = 0;
88	      if (::waitpid(child_pid, &wstat, WNOHANG) == child_pid) {
89	        int status = -1;
90	        if (WIFEXITED(wstat)) status = WEXITSTATUS(wstat);
91	        else if (WIFSIGNALED(wstat)) status = 128 + WTERMSIG(wstat);
92	        throw ChildExitedDuringConnect{status};
93	      }
94	    }
95	    std::this_thread::sleep_for(std::chrono::milliseconds(20));
96	  }
97	  throw std::runtime_error("connect_loopback: timed out waiting for QEMU "
98	                           "gdbstub");
99	}
100	
101	inline auto spawn_qemu(const std::string& binary,
102	                       const std::string& elf,
103	                       uint16_t gdb_port,
104	                       const std::string& shared_mem_path = {},
105	                       uint64_t shared_mem_size = 0) -> pid_t
106	{
107	  const pid_t pid = ::fork();
108	  if (pid < 0)
109	    throw std::runtime_error(std::string{"spawn_qemu: fork: "}
110	                             + std::strerror(errno));
111	  if (pid == 0) {
112	    const std::string gdb_arg = "tcp::" + std::to_string(gdb_port);
113	    const std::string mem_obj = "memory-backend-file,id=mem,share=on,mem-path="
114	                              + shared_mem_path
115	                              + ",size=" + std::to_string(shared_mem_size);
116	    std::vector<const char*> argv;
117	    argv.push_back(binary.c_str());
118	    if (!shared_mem_path.empty()) {
119	      argv.push_back("-object");
120	      argv.push_back(mem_obj.c_str());
121	      argv.push_back("-machine");
122	      argv.push_back("virt,memory-backend=mem");
123	    } else {
124	      argv.push_back("-M");
125	      argv.push_back("virt");
126	    }
127	    argv.push_back("-bios");
128	    argv.push_back("none");
129	    argv.push_back("-nographic");
130	    argv.push_back("-semihosting-config");
131	    argv.push_back("enable=on,target=native");
132	    argv.push_back("-kernel");
133	    argv.push_back(elf.c_str());
134	    argv.push_back("-gdb");
135	    argv.push_back(gdb_arg.c_str());
136	    argv.push_back("-S");
137	    argv.push_back(nullptr);
138	
139	    ::execv(binary.c_str(), const_cast<char* const*>(argv.data()));
140	    std::fprintf(stderr, "exec %s: %s\n", binary.c_str(),
141	                 std::strerror(errno));
142	    ::_exit(127);
143	  }
144	  return pid;
145	}
