194	// Sends one P packet, throwing with context if the stub answers anything
195	// other than "OK". A missing register name is silently skipped: not every
196	// QEMU build advertises every PMP slot or extension CSR, so absence isn't
197	// a fatal mismatch.
198	inline void try_write_named(gdbstub::Session& sess,
199	                            const gdbstub::RegMap& map,
200	                            const std::string& name,
201	                            uint64_t value)
202	{
203	  const auto it = map.name_to_num.find(name);
204	  if (it == map.name_to_num.end()) return;
205	  auto reply = sess.send_command(gdbstub::encode_p_body(it->second, value));
206	  if (reply != "OK")
207	    throw std::runtime_error("gdbstub: P packet for " + name + " replied "
208	                             + reply);
209	}
210	
211	inline void try_write_named_bytes(gdbstub::Session& sess,
212	                                  const gdbstub::RegMap& map,
213	                                  const std::string& name,
214	                                  const uint8_t* bytes,
215	                                  std::size_t n)
216	{
217	  const auto it = map.name_to_num.find(name);
218	  if (it == map.name_to_num.end()) return;
219	  auto reply = sess.send_command(
220	    gdbstub::encode_p_body_bytes(it->second, bytes, n));
221	  if (reply != "OK")
222	    throw std::runtime_error("gdbstub: P packet for " + name + " replied "
223	                             + reply);
224	}
