226	// FP register names as advertised by QEMU's gdbstub static XML feature.
227	// Order matches f0..f31.
228	inline constexpr std::array<const char*, 32> kFprNames = {{
229	  "ft0", "ft1", "ft2",  "ft3",  "ft4", "ft5", "ft6", "ft7",
230	  "fs0", "fs1", "fa0",  "fa1",  "fa2", "fa3", "fa4", "fa5",
231	  "fa6", "fa7", "fs2",  "fs3",  "fs4", "fs5", "fs6", "fs7",
232	  "fs8", "fs9", "fs10", "fs11", "ft8", "ft9", "ft10","ft11",
233	}};
234	
235	inline constexpr std::array<std::pair<const char*, uint64_t hybrid_state_v1::*>,
236	                            13>
237	  kCsrByName = {{
238	    {"mstatus",  &hybrid_state_v1::mstatus},
239	    {"mepc",     &hybrid_state_v1::mepc},
240	    {"mtvec",    &hybrid_state_v1::mtvec},
241	    {"mcause",   &hybrid_state_v1::mcause},
242	    {"mtval",    &hybrid_state_v1::mtval},
243	    {"mscratch", &hybrid_state_v1::mscratch},
244	    {"medeleg",  &hybrid_state_v1::medeleg},
245	    {"mideleg",  &hybrid_state_v1::mideleg},
246	    {"mip",      &hybrid_state_v1::mip},
247	    {"mie",      &hybrid_state_v1::mie},
248	    {"mcycle",   &hybrid_state_v1::mcycle},
249	    {"minstret", &hybrid_state_v1::minstret},
250	    {"satp",     &hybrid_state_v1::satp},
251	  }};
