316	// Top-level: spawns QEMU, restores state, waits for exit, returns exit
317	// status (or 128 + signal for abnormal termination).
318	inline auto run_qemu_handback(const std::string& qemu_binary,
319	                              const std::string& elf_path,
320	                              const hybrid_state_v1& state,
321	                              const std::string& shared_mem_path = {},
322	                              uint64_t shared_mem_size = 0) -> int
323	{
324	  const auto port = detail::pick_free_port();
325	  spdlog::info("hybrid handback: spawning {} -gdb tcp::{} -S",
326	               qemu_binary, port);
327	  const pid_t pid = detail::spawn_qemu(qemu_binary, elf_path, port,
328	                                       shared_mem_path, shared_mem_size);
329	
330	  try {
331	    restore_state_via_gdbstub(port, state, pid);
332	  } catch (const detail::ChildExitedDuringConnect& d) {
333	    return d.status;
334	  } catch (...) {
335	    ::kill(pid, SIGKILL);
336	    int wstat = 0;
337	    ::waitpid(pid, &wstat, 0);
338	    throw;
339	  }
340	
341	  int wstat = 0;
342	  if (::waitpid(pid, &wstat, 0) < 0)
343	    throw std::runtime_error(std::string{"waitpid: "}
344	                             + std::strerror(errno));
345	  if (WIFEXITED(wstat)) return WEXITSTATUS(wstat);
346	  if (WIFSIGNALED(wstat)) return 128 + WTERMSIG(wstat);
347	  return -1;
348	}
