72	static struct qemu_plugin_register *find_reg(GArray *regs, const char *name)
73	{
74	    for (guint i = 0; i < regs->len; i++) {
75	        qemu_plugin_reg_descriptor *rd =
76	            &g_array_index(regs, qemu_plugin_reg_descriptor, i);
77	        if (g_ascii_strcasecmp(rd->name, name) == 0) {
78	            return rd->handle;
79	        }
80	    }
81	    return NULL;
82	}
