276	QEMU_PLUGIN_EXPORT int qemu_plugin_install(qemu_plugin_id_t id,
277	                                           const qemu_info_t *info,
278	                                           int argc, char **argv)
279	{
280	    (void) info;
281	    for (int i = 0; i < argc; i++) {
282	        g_auto(GStrv) tok = g_strsplit(argv[i], "=", 2);
283	        if (g_strcmp0(tok[0], "outfile") == 0 && tok[1]) {
284	            outfile_path = g_strdup(tok[1]);
285	        } else {
286	            fprintf(stderr, "hybrid_handoff: unknown option: %s\n", argv[i]);
287	            return -1;
288	        }
289	    }
290	    if (!outfile_path) {
291	        fputs("hybrid_handoff: outfile=PATH is required\n", stderr);
292	        return -1;
293	    }
294	
295	    vcpu_state = qemu_plugin_scoreboard_new(sizeof(VcpuRegs));
296	    qemu_plugin_register_vcpu_tb_trans_cb(id, vcpu_tb_trans);
297	    return 0;
298	}
