1	// StateDrain is the dual of ResumeDriver: halt the hart via the Debug Module,
2	// read x1..x31 + DPC + FPR + M-mode CSRs + PMP + vector CSRs via Abstract
3	// Commands, populate hybrid_state_v1. Vector data registers (v0..v31) are
4	// not yet read because the Debug Module's coverage of vector regs depends
5	// on the implementation; the slot stays zero until Phase 5 wires it up.
6	//
7	// Reuses ResumeDriver's DM register constants and DmiBus interface.
8	
9	#pragma once
10	
11	#include "hybrid/abstract_command.hpp"
12	#include "hybrid/dmi_poll.hpp"
13	#include "hybrid/resume_driver.hpp"
14	#include "hybrid/state_abi.h"
15	
16	#include <cstdint>
17	
18	namespace hybrid
19	{
20	
21	class StateDrain
22	{
23	public:
24	  using RD = ResumeDriver;
25	
26	  static constexpr uint16_t kCsrVl    = 0xc20;
27	  static constexpr uint16_t kCsrVtype = 0xc21;
28	  static constexpr uint16_t kCsrVlenb = 0xc22;
29	
30	  explicit StateDrain(DmiBus& bus)
31	      : bus_{bus}
32	  {}
33	
34	  // Drain GPRs (x1..x31) + PC into a fresh state. FP/CSR/V slots are zero;
35	  // the caller is expected to fill them via merge_pass_through() if it has
36	  // the original input state from QEMU 1.
37	  auto drain() -> hybrid_state_v1
38	  {
39	    bus_.write(RD::kDmcontrol, RD::kDmcontrolDmactive);
40	    bus_.write(RD::kDmcontrol, RD::kDmcontrolDmactive | RD::kDmcontrolHaltreq);
41	    poll_until_set(bus_, RD::kDmstatus, RD::kDmstatusAllhalted,
42	                   "StateDrain halt");
43	
44	    hybrid_state_v1 state{};
45	    state.magic   = HYBRID_STATE_MAGIC;
46	    state.version = HYBRID_STATE_VERSION;
47	    state.flags   = HYBRID_FLAG_RV64;
48	    state.priv    = 3;
49	
50	    for (uint16_t i = 1; i < 32; ++i)
51	      state.gpr[i] = read_64bit_register(regno_gpr(i));
52	
53	    state.pc = read_64bit_register(regno_csr(RD::kCsrDpc));
54	    return state;
55	  }
56	
57	  // Returns a state where GPRs (x1..x31) + PC are freshly drained from the
58	  // hart but FP, M-mode CSRs, PMP, and vector state are copied from the
59	  // input snapshot. Used by HandoffController to round-trip QEMU 1's full
60	  // architectural state through vsim without paying the ~100x DM Abstract
61	  // Command overhead for fields the ROI did not modify.
62	  auto drain_with_passthrough(const hybrid_state_v1& input) -> hybrid_state_v1
63	  {
64	    auto state    = drain();
65	    state.flags   = input.flags;
66	    state.priv    = input.priv;
67	    state.hart_id = input.hart_id;
68	
69	    for (int i = 0; i < 32; ++i) state.fpr[i] = input.fpr[i];
70	
71	    state.mstatus  = input.mstatus;
72	    state.mepc     = input.mepc;
73	    state.mtvec    = input.mtvec;
74	    state.mcause   = input.mcause;
75	    state.mtval    = input.mtval;
76	    state.mscratch = input.mscratch;
77	    state.medeleg  = input.medeleg;
78	    state.mideleg  = input.mideleg;
79	    state.mip      = input.mip;
80	    state.mie      = input.mie;
81	    state.mcycle   = input.mcycle;
82	    state.minstret = input.minstret;
83	    state.satp     = input.satp;
84	
85	    for (int i = 0; i < HYBRID_PMP_CFG_NUM; ++i)
86	      state.pmpcfg[i]  = input.pmpcfg[i];
87	    for (int i = 0; i < HYBRID_PMP_ADDR_NUM; ++i)
88	      state.pmpaddr[i] = input.pmpaddr[i];
89	
90	    state.vstart = input.vstart;
91	    state.vtype  = input.vtype;
92	    state.vl     = input.vl;
93	    state.vlenb  = input.vlenb;
94	    for (std::size_t i = 0; i < sizeof(state.vreg); ++i)
95	      state.vreg[i] = input.vreg[i];
96	
97	    return state;
98	  }
99	
100	private:
101	  auto read_64bit_register(uint16_t regno) -> uint64_t
102	  {
103	    bus_.write(RD::kCommand, access_register_command(regno, AarSize::Bits64,
104	                                                     /*write=*/false));
105	    poll_until_clear(bus_, RD::kAbstractcs, RD::kAbstractcsBusy,
106	                     "StateDrain read_register");
107	    // If the hardware DM does not implement Abstract access for this
108	    // register, cmderr is set sticky and DATA0/DATA1 hold stale bytes.
109	    // Clear the error and report 0 for that field so the next read can
110	    // proceed - a missing CSR mirrors as zero rather than corrupting the
111	    // adjacent slot.
112	    const auto status = bus_.read(RD::kAbstractcs);
113	    if ((status & RD::kAbstractcsCmderrMask) != 0u) {
114	      bus_.write(RD::kAbstractcs, RD::kAbstractcsCmderrMask);
115	      return 0u;
116	    }
117	    const uint64_t lo = bus_.read(RD::kData0);
118	    const uint64_t hi = bus_.read(RD::kData1);
119	    return lo | (hi << 32);
120	  }
121	
122	  DmiBus& bus_;
123	};
