19	class ResumeDriver
20	{
21	public:
22	  static constexpr uint8_t kData0      = 0x04;
23	  static constexpr uint8_t kData1      = 0x05;
24	  static constexpr uint8_t kDmcontrol  = 0x10;
25	  static constexpr uint8_t kDmstatus   = 0x11;
26	  static constexpr uint8_t kAbstractcs = 0x16;
27	  static constexpr uint8_t kCommand    = 0x17;
28	
29	  static constexpr uint16_t kCsrDpc = 0x7B1;
30	
31	  static constexpr uint32_t kDmcontrolDmactive  = 1u << 0;
32	  static constexpr uint32_t kDmcontrolResumereq = 1u << 30;
33	  static constexpr uint32_t kDmcontrolHaltreq   = 1u << 31;
34	
35	  static constexpr uint32_t kDmstatusAllhalted    = 1u << 9;
36	  static constexpr uint32_t kDmstatusAllresumeack = 1u << 17;
37	
38	  static constexpr uint32_t kAbstractcsBusy        = 1u << 12;
39	  static constexpr uint32_t kAbstractcsCmderrMask  = 0x7u << 8;
40	
41	  static constexpr unsigned kPollIterations = kDmiPollIterations;
42	
43	  explicit ResumeDriver(DmiBus& bus)
44	      : bus_{bus}
45	  {}
46	
47	  void resume(const hybrid_state_v1& state)
48	  {
49	    if (state.magic != HYBRID_STATE_MAGIC)
50	      throw std::runtime_error("ResumeDriver::resume: bad magic");
51	    if (state.version != HYBRID_STATE_VERSION)
52	      throw std::runtime_error("ResumeDriver::resume: unsupported version");
53	
54	    // dmactive must transition 0->1 in its own write before any other
55	    // DMCONTROL bit is honored (RISC-V Debug Spec).
56	    bus_.write(kDmcontrol, kDmcontrolDmactive);
57	    request_halt();
58	    poll_until_set(bus_, kDmstatus, kDmstatusAllhalted, "ResumeDriver halt");
59	
60	    // x0 is hard-wired zero; skip it.
61	    for (uint16_t i = 1; i < 32; ++i)
62	      write_64bit_register(regno_gpr(i), state.gpr[i]);
63	
64	    // FP/CSR/V state is carried through vsim by the HandoffController
65	    // pass-through merge: vsim's ROI generally doesn't touch those fields
66	    // and the Andes DM Abstract Command coverage for them is incomplete.
67	    // The resume path therefore only programs GPRs + DPC. To extend to
68	    // FP or vector data ROIs, opt-in here once the DM coverage is verified.
69	    write_64bit_register(regno_csr(kCsrDpc), state.pc);
70	
71	    request_resume();
72	    poll_until_set(bus_, kDmstatus, kDmstatusAllresumeack,
73	                   "ResumeDriver resume");
74	  }
75	
76	private:
77	  void request_halt()
78	  {
79	    bus_.write(kDmcontrol, kDmcontrolDmactive | kDmcontrolHaltreq);
80	  }
81	
82	  void request_resume()
83	  {
84	    bus_.write(kDmcontrol, kDmcontrolDmactive | kDmcontrolResumereq);
85	  }
86	
87	  void write_64bit_register(uint16_t regno, uint64_t value)
88	  {
89	    bus_.write(kData0, uint32_t(value & 0xffffffffu));
90	    bus_.write(kData1, uint32_t((value >> 32) & 0xffffffffu));
91	    bus_.write(kCommand,
92	               access_register_command(regno, AarSize::Bits64, /*write=*/true));
93	    poll_until_clear(bus_, kAbstractcs, kAbstractcsBusy,
94	                     "ResumeDriver write_register");
95	    clear_cmderr_if_set();
96	  }
97	
98	  // Per Debug Spec, abstractcs.cmderr is sticky: a new Abstract Command
99	  // is silently rejected (or returns "busy") until the bits are cleared
100	  // by writing W1C. We tolerate per-register failures (e.g., when the
101	  // hardware DM does not implement Abstract access for a particular FPR
102	  // or CSR) by clearing the error so the next register can be programmed.
103	  void clear_cmderr_if_set()
104	  {
105	    const auto status = bus_.read(kAbstractcs);
106	    if ((status & kAbstractcsCmderrMask) != 0u)
107	      bus_.write(kAbstractcs, kAbstractcsCmderrMask);
108	  }
109	
110	  DmiBus& bus_;
111	};
