1	// Glues CsrTrigger and StateDrain. The simulator's run-loop calls on_retire
2	// once per committed PC; the controller decides via the trigger map whether
3	// to drain state and returns the populated hybrid_state_v1 if so. The
4	// caller (simulator.hpp) is responsible for writing the file and exiting
5	// with EXIT_HANDOFF_TO_QEMU.
6	
7	#pragma once
8	
9	#include "hybrid/csr_trigger.hpp"
10	#include "hybrid/insn_match.h"
11	#include "hybrid/resume_driver.hpp"
12	#include "hybrid/state_abi.h"
13	#include "hybrid/state_drain.hpp"
14	
15	#include <cstdint>
16	#include <optional>
17	#include <utility>
18	
19	namespace hybrid
20	{
21	
22	class HandoffController
23	{
24	public:
25	  HandoffController(CsrTrigger trigger, DmiBus& bus)
26	      : trigger_{std::move(trigger)}, drain_{bus}
27	  {}
28	
29	  // Optional snapshot of the QEMU 1 input state. When set, drain merges
30	  // FP/CSR/V fields from the snapshot into the freshly drained GPRs+PC,
31	  // round-tripping the full architectural state without paying the DM
32	  // Abstract Command overhead for every field on every handoff.
33	  void set_passthrough_input(const hybrid_state_v1* input)
34	  {
35	    passthrough_ = input;
36	  }
37	
38	  template<typename GprProbe>
39	  auto on_retire(uint64_t pc, GprProbe&& read_gpr)
40	    -> std::optional<hybrid_state_v1>
41	  {
42	    const auto hit = trigger_.lookup(pc);
43	    if (!hit) return std::nullopt;
44	
45	    bool fire = false;
46	    switch (hit->kind) {
47	    case HYBRID_HANDOFF_EXIT:
48	      fire = true;
49	      break;
50	    case HYBRID_HANDOFF_RUNTIME: {
51	      const auto rs1 = decode_csrrw_rs1(hit->insn);
52	      fire = (read_gpr(rs1) == 1u);
53	      break;
54	    }
55	    case HYBRID_HANDOFF_ENTER:  // entry is QEMU's job; vsim ignores it
56	    case HYBRID_HANDOFF_NONE:
57	      break;
58	    }
59	    if (!fire) return std::nullopt;
60	    if (passthrough_) return drain_.drain_with_passthrough(*passthrough_);
61	    return drain_.drain();
62	  }
63	
64	private:
65	  CsrTrigger trigger_;
66	  StateDrain drain_;
67	  const hybrid_state_v1* passthrough_ = nullptr;
68	};
69	
70	}  // namespace hybrid
